const notionDocs = $('Retrieve Notion Pages').all();
const substackDocs = $('Retrieve Substack Posts').all();
const linkedinDocs = $('Retrieve LinkedIn Posts').all();

const uniqueNotion = Array.from(new Map(notionDocs.map(d => [d.json.document?.pageContent || '', d])).values());
const uniqueSubstack = Array.from(new Map(substackDocs.map(d => [d.json.document?.pageContent || '', d])).values());
const uniqueLinkedin = Array.from(new Map(linkedinDocs.map(d => [d.json.document?.pageContent || '', d])).values());

let ragContext = '### RELEVANT HISTORICAL CONTENT & KNOWLEDGE (RAG) ###\n\n';

function addDocs(docs, sourceName) {
  if (docs.length === 0) return;
  docs.forEach((doc, idx) => {
    const content = doc.json.document?.pageContent || '';
    if (!content) return;
    const firstLine = content.split('\n')[0].trim();
    const title = firstLine.length > 60 ? `${firstLine.substring(0, 60).trim()}...` : firstLine;
    ragContext += `[Source: ${sourceName} | Title: ${title || 'Untitled'}]\n`;
    ragContext += `Content: ${content.substring(0, 1000)}\n`;
    ragContext += `---\n\n`;
  });
}

addDocs(uniqueNotion, 'Notion');
addDocs(uniqueSubstack, 'Substack');
addDocs(uniqueLinkedin, 'LinkedIn');

return [{ json: { rag_context: ragContext } }];

const ragContext = $('Format RAG Context').first()?.json?.rag_context || '';
const fs = require('fs');
let persona = '';
try {
  persona = fs.readFileSync('/etc/n8n/agents/giusy.md', 'utf8');
} catch (e) {
  persona = 'Warm, brilliant AI Marketing Director named Giusy.';
}

let strategy = '';
try {
  strategy = fs.readFileSync('/etc/n8n/workflows/prompts/content_strategy.md', 'utf8');
} catch (e) {
  strategy = 'Standard content creation rules.';
}

let positioning = '';
try {
  positioning = fs.readFileSync('/etc/n8n/workflows/prompts/usp_market_positioning.md', 'utf8');
} catch (e) { 
  positioning = 'Standard positioning rules.';
}

let structure = '';
try {
  structure = fs.readFileSync('/etc/n8n/workflows/prompts/substack_post_structure.md', 'utf8');
} catch (e) {
  structure = 'Standard Substack post structure rules.';
}

return [{ json: { text: ragContext, giusy_persona: persona, content_strategy: strategy, usp_positioning: positioning, substack_structure: structure } }];

const raw = $input.first().json.content || $input.first().json.response || '';
let jsonStr = raw.trim();

let title = '';
let substack_content = '';
let reasoning = '';
let parsed = false;

try {
  let cleanStr = jsonStr;
  const firstBrace = cleanStr.indexOf('{');
  const lastBrace = cleanStr.lastIndexOf('}');
  if (firstBrace !== -1 && lastBrace !== -1 && lastBrace > firstBrace) {
    cleanStr = cleanStr.substring(firstBrace, lastBrace + 1);
  }
  cleanStr = cleanStr.replace(/[\u201C\u201D\u201E\u201F\u2033\u2036]/g, '"');
  const obj = JSON.parse(cleanStr);
  title = obj.title || '';
  substack_content = obj.substack_content || '';
  reasoning = obj.brief_strategic_reasoning || '';
  parsed = true;
} catch (e) {
  // standard parsing failed
}

if (!parsed) {
  const titleMatch = jsonStr.match(/"title"\s*:\s*"([\s\S]*?)"\s*,/);
  if (titleMatch) title = titleMatch[1];

  const postMatch = jsonStr.match(/"substack_content"\s*:\s*"([\s\S]*?)"\s*,\s*"brief_strategic_reasoning"/);
  if (postMatch) {
    substack_content = postMatch[1];
  } else {
    const altMatch = jsonStr.match(/"substack_content"\s*:\s*"([\s\S]*?)"\s*}/);
    if (altMatch) {
      substack_content = altMatch[1];
    } else {
      substack_content = raw.replace(/```json/g, '').replace(/```/g, '').trim();
    }
  }
  const reasonMatch = jsonStr.match(/"brief_strategic_reasoning"\s*:\s*"([\s\S]*?)"/);
  if (reasonMatch) {
    reasoning = reasonMatch[1];
  }

  title = title
    .replace(/\\n/g, '\n')
    .replace(/\\"/g, '"')
    .replace(/\\'/g, "'")
    .replace(/\\\\/g, '\\');
  substack_content = substack_content
    .replace(/\\n/g, '\n')
    .replace(/\\"/g, '"')
    .replace(/\\'/g, "'")
    .replace(/\\\\/g, '\\');
  reasoning = reasoning
    .replace(/\\n/g, '\n')
    .replace(/\\"/g, '"')
    .replace(/\\'/g, "'")
    .replace(/\\\\/g, '\\');
}

const notionDocs = $('Retrieve Notion Pages').all();
const substackDocs = $('Retrieve Substack Posts').all();
const linkedinDocs = $('Retrieve LinkedIn Posts').all();

const fs = require('fs');
try {
  fs.writeFileSync('/tmp/substack_doc.json', JSON.stringify(substackDocs.map(d => d.json), null, 2));
  fs.writeFileSync('/tmp/notion_doc.json', JSON.stringify(notionDocs.map(d => d.json), null, 2));
  fs.writeFileSync('/tmp/linkedin_doc.json', JSON.stringify(linkedinDocs.map(d => d.json), null, 2));
} catch (err) {}

const uniqueNotion = Array.from(new Map(notionDocs.map(d => [d.json.document?.pageContent || '', d])).values());
const uniqueSubstack = Array.from(new Map(substackDocs.map(d => [d.json.document?.pageContent || '', d])).values());
const uniqueLinkedin = Array.from(new Map(linkedinDocs.map(d => [d.json.document?.pageContent || '', d])).values());

const sources = [];
const sourcesObj = {
  Notion: [],
  Substack: [],
  LinkedIn: []
};

function addSource(docs, label, key) {
  docs.forEach(d => {
    const content = d.json.document?.pageContent || '';
    if (content) {
      const firstLine = content.split('\n')[0].trim();
      const shortTitle = firstLine.length > 80 ? firstLine.substring(0, 80) + '...' : firstLine;
      const titleVal = `"${shortTitle}"`;
      sources.push(`${label}: ${titleVal}`);
      sourcesObj[key].push(titleVal);
    }
  });
}

addSource(uniqueNotion, 'Notion', 'Notion');
addSource(uniqueSubstack, 'Substack', 'Substack');
addSource(uniqueLinkedin, 'LinkedIn', 'LinkedIn');

const sourcesStr = sources.length > 0 ? sources.join(', ') : 'None';

return [{ json: { title, substack_content, reasoning, sources_str: sourcesStr, sources_obj: sourcesObj } }];

const title = $input.first().json.title || 'Untitled Substack Post';
const content = $input.first().json.substack_content || '';
const reasoning = $input.first().json.reasoning || '';
const sources_str = $input.first().json.sources_str || '';

const lines = content.split('\n');
const children = [];

function safeText(str, limit = 1990) {
  if (!str) return '';
  return str.length > limit ? str.substring(0, limit - 3) + '...' : str;
}

function parseMarkdownToRichText(text) {
  if (!text) return [];
  const safeTxt = safeText(text);
  const richText = [];
  const tokenRegex = /(\*\*.*?\*\*|\*.*?\*|`.*?`|\[.*?\]\(.*?\))/g;
  const parts = safeTxt.split(tokenRegex);

  for (const part of parts) {
    if (!part) continue;
    if (part.startsWith('**') && part.endsWith('**')) {
      richText.push({
        type: 'text',
        text: { content: part.slice(2, -2) },
        annotations: { bold: true }
      });
    } else if (part.startsWith('*') && part.endsWith('*')) {
      richText.push({
        type: 'text',
        text: { content: part.slice(1, -1) },
        annotations: { italic: true }
      });
    } else if (part.startsWith('`') && part.endsWith('`')) {
      richText.push({
        type: 'text',
        text: { content: part.slice(1, -1) },
        annotations: { code: true }
      });
    } else if (part.startsWith('[') && part.includes('](')) {
      const closeBracket = part.indexOf(']');
      const linkText = part.slice(1, closeBracket);
      const linkUrl = part.slice(closeBracket + 2, -1);
      richText.push({
        type: 'text',
        text: {
          content: linkText,
          link: { url: linkUrl }
        }
      });
    } else {
      richText.push({
        type: 'text',
        text: { content: part }
      });
    }
  }

  if (richText.length === 0) {
    richText.push({
      type: 'text',
      text: { content: safeTxt }
    });
  }
  return richText;
}

if (reasoning) {
  children.push({
    "object": "block",
    "type": "callout",
    "callout": {
      "rich_text": [
        {
          "type": "text",
          "text": {
            "content": safeText("Strategic Reasoning: " + reasoning)
          },
          "annotations": {
            "italic": true,
            "bold": true
          }
        }
      ],
      "icon": {
        "emoji": "💡"
      },
      "color": "blue_background"
    }
  });
}

if (sources_str) {
  children.push({
    "object": "block",
    "type": "callout",
    "callout": {
      "rich_text": [
        {
          "type": "text",
          "text": {
            "content": safeText("Sources Used: " + sources_str)
          }
        }
      ],
      "icon": {
        "emoji": "📚"
      },
      "color": "gray_background"
    }
  });
}

let inCodeBlock = false;
let codeContent = [];
let codeLanguage = 'plain text';

let inTable = false;
let tableRows = [];
let tableWidth = 0;

for (let line of lines) {
  let trimmed = line.trim();

  if (trimmed.startsWith('```')) {
    if (inTable) {
      children.push({
        "object": "block",
        "type": "table",
        "table": {
          "table_width": tableWidth,
          "has_column_header": true,
          "children": tableRows.map(row => ({
            "object": "block",
            "type": "table_row",
            "table_row": {
              "cells": row.map(cell => parseMarkdownToRichText(cell))
            }
          }))
        }
      });
      inTable = false;
      tableRows = [];
    }

    if (inCodeBlock) {
      children.push({
        "object": "block",
        "type": "code",
        "code": {
          "rich_text": [{ "type": "text", "text": { "content": safeText(codeContent.join('\n')) } }],
          "language": codeLanguage
        }
      });
      codeContent = [];
      inCodeBlock = false;
    } else {
      inCodeBlock = true;
      const lang = trimmed.substring(3).trim();
      codeLanguage = lang || 'plain text';
    }
    continue;
  }

  if (inCodeBlock) {
    codeContent.push(line);
    continue;
  }

  if (trimmed.startsWith('|') && trimmed.endsWith('|')) {
    if (/^[|\s:-]+$/.test(trimmed)) {
      continue;
    }
    const cells = trimmed.split('|').slice(1, -1).map(c => c.trim());
    if (!inTable) {
      inTable = true;
      tableRows = [cells];
      tableWidth = cells.length;
    } else {
      tableRows.push(cells);
    }
    continue;
  } else {
    if (inTable) {
      children.push({
        "object": "block",
        "type": "table",
        "table": {
          "table_width": tableWidth,
          "has_column_header": true,
          "children": tableRows.map(row => ({
            "object": "block",
            "type": "table_row",
            "table_row": {
              "cells": row.map(cell => parseMarkdownToRichText(cell))
            }
          }))
        }
      });
      inTable = false;
      tableRows = [];
    }
  }

  if (!trimmed) {
    continue;
  }

  if (trimmed.startsWith('### ')) {
    children.push({
      "object": "block",
      "type": "heading_3",
      "heading_3": {
        "rich_text": parseMarkdownToRichText(trimmed.substring(4))
      }
    });
  } else if (trimmed.startsWith('## ')) {
    children.push({
      "object": "block",
      "type": "heading_2",
      "heading_2": {
        "rich_text": parseMarkdownToRichText(trimmed.substring(3))
      }
    });
  } else if (trimmed.startsWith('# ')) {
    children.push({
      "object": "block",
      "type": "heading_1",
      "heading_1": {
        "rich_text": parseMarkdownToRichText(trimmed.substring(2))
      }
    });
  } else if (trimmed.startsWith('* ') || trimmed.startsWith('- ')) {
    children.push({
      "object": "block",
      "type": "bulleted_list_item",
      "bulleted_list_item": {
        "rich_text": parseMarkdownToRichText(trimmed.substring(2))
      }
    });
  } else if (/^\d+\.\s/.test(trimmed)) {
    const contentStart = trimmed.indexOf(' ') + 1;
    children.push({
      "object": "block",
      "type": "numbered_list_item",
      "numbered_list_item": {
        "rich_text": parseMarkdownToRichText(trimmed.substring(contentStart))
      }
    });
  } else {
    children.push({
      "object": "block",
      "type": "paragraph",
      "paragraph": {
        "rich_text": parseMarkdownToRichText(line)
      }
    });
  }
}

if (inTable) {
  children.push({
    "object": "block",
    "type": "table",
    "table": {
      "table_width": tableWidth,
      "has_column_header": true,
      "children": tableRows.map(row => ({
        "object": "block",
        "type": "table_row",
        "table_row": {
          "cells": row.map(cell => parseMarkdownToRichText(cell))
        }
      }))
    }
  });
}

const chunkedChildren = children.slice(0, 100);

const payload = {
  "parent": { "database_id": "3956e98d4ef880c3bce5e31729afdf38" },
  "properties": {
    "Name": {
      "title": [
        {
          "text": {
            "content": safeText(title)
          }
        }
      ]
    },
    "Status": {
      "status": {
        "name": "Draft"
      }
    }
  },
  "children": chunkedChildren
};

return [{ json: { payload, title, reasoning } }];

